// src/pages/DetectPage.jsx
import startImage from '../assets/startpage.png';

function DetectPage() {
  return (
    <div className="relative w-full min-h-screen bg-white overflow-hidden">
      {/* 흐릿한 배경 이미지 */}
      <img
        src={startImage}
        alt="배경"
        className="absolute top-0 left-0 w-full h-full object-cover opacity-20 blur-2xl -z-10"
      />

      {/* 중앙 콘텐츠 */}
      <div className="relative z-10 flex flex-col items-center justify-center min-h-screen px-4 text-center">
        <h1 className="text-2xl md:text-3xl font-bold text-gray-800 mb-4">
          AI에게 물어보세요!
        </h1>
        <p className="text-gray-600 mb-8">
          입력한 아파트의 전세가와 매매가를 비교하여<br />
          깡통 전세 여부를 예측합니다.
        </p>

        {/* 입력창 */}
        <div className="w-full max-w-xl bg-white rounded-full shadow-md p-2 flex items-center border border-blue-300">
          <input
            type="text"
            placeholder="예: 서울 송파구 잠실동 123-4"
            className="flex-1 px-4 py-2 outline-none rounded-full"
          />
          <button className="text-blue-600 px-4 text-xl hover:text-blue-800">
            ➤
          </button>
        </div>
      </div>
    </div>
  );
}

export default DetectPage;
